/**
 * Get configured root folder name for current environment
 * Requirements: env-folder-naming 2.1 - Frontend Folder Name Discovery
 */
@Get('folder-name')
async getFolderName(): Promise<IFolderNameResponse> {
  try {
    const folderName = await this.attachmentService.getRootFolderName();

    this.logger.debug(`Root folder name retrieved: ${folderName}`);

    return {
      success: true,
      folderName,
    };
  } catch (error) {
    this.logger.error('Failed to retrieve root folder name:', error);

    return {
      success: false,
      error: 'Failed to retrieve folder configuration',
    };
  }
}
```

